class BudgetTracker:
    def __init__(self, limit: int) -> None:
        self.__limit = limit          # mangled: _BudgetTracker__limit
        self._spent = 0               # protected by convention

    # Public API
    def charge(self, tokens: int) -> None:
        if tokens < 0:
            raise ValueError("tokens must be non-negative")
        remaining = self.__limit - self._spent
        if tokens > remaining:
            raise RuntimeError(f"Budget exceeded: need {tokens}, have {remaining}")
        self._spent += tokens

    @property
    def remaining(self) -> int:
        return self.__limit - self._spent

    @property
    def spent(self) -> int:
        return self._spent

class GenerationConfig:
    _VALID_ROLES = {"user", "assistant", "system"}

    def __init__(self, temperature: float = 1.0, max_tokens: int = 1024) -> None:
        self.temperature = temperature      # goes through setter
        self.max_tokens = max_tokens        # goes through setter
        self._seed: int | None = None

    @property
    def temperature(self) -> float:
        return self._temperature

    @temperature.setter
    def temperature(self, value: float) -> None:
        if not 0.0 <= value <= 2.0:
            raise ValueError(f"temperature must be in [0.0, 2.0], got {value}")
        self._temperature = value

    @property
    def max_tokens(self) -> int:
        return self._max_tokens

    @max_tokens.setter
    def max_tokens(self, value: int) -> None:
        if value < 1 or value > 32_768:
            raise ValueError(f"max_tokens must be in [1, 32768], got {value}")
        self._max_tokens = value

    def as_dict(self) -> dict:
        d: dict = {"temperature": self._temperature, "max_tokens": self._max_tokens}
        if self._seed is not None:
            d["seed"] = self._seed
        return d

from __future__ import annotations
from dataclasses import dataclass, field
from typing import Literal

Role = Literal["user", "assistant", "system"]


@dataclass
class Message:
    role: Role
    content: str
    tokens: int


class TokenLimitedSession:
    """
    Encapsulates a conversation with a hard token budget.

    Public interface:
      add_turn(role, content, tokens) -> None
      messages -> tuple[Message, ...]   (read-only snapshot)
      remaining_tokens -> int
      close() -> None
    """

    def __init__(self, session_id: str, token_limit: int) -> None:
        self._session_id = session_id
        self.__token_limit = token_limit
        self._spent = 0
        self._messages: list[Message] = []
        self._closed = False

    # ---- public interface ------------------------------------------------

    def add_turn(self, role: Role, content: str, tokens: int) -> None:
        """Add one conversation turn, enforcing ordering and budget."""
        self._assert_open()
        self._check_role_order(role)
        self._check_budget(tokens)
        self._messages.append(Message(role=role, content=content, tokens=tokens))
        self._spent += tokens

    @property
    def messages(self) -> tuple[Message, ...]:
        """Immutable snapshot of the conversation history."""
        return tuple(self._messages)

    @property
    def remaining_tokens(self) -> int:
        return self.__token_limit - self._spent

    def close(self) -> None:
        """Mark session as closed; no further turns may be added."""
        self._closed = True

    # ---- private enforcement -----------------------------------------------

    def _assert_open(self) -> None:
        if self._closed:
            raise RuntimeError(f"Session {self._session_id!r} is closed")

    def _check_role_order(self, role: Role) -> None:
        if role == "system":
            return  # system messages are always allowed
        if self._messages:
            last = self._messages[-1].role
            if last == role and role != "system":
                raise ValueError(
                    f"Role ordering violation: cannot follow '{last}' with '{role}'"
                )

    def _check_budget(self, tokens: int) -> None:
        if tokens < 0:
            raise ValueError("tokens must be non-negative")
        if self._spent + tokens > self.__token_limit:
            raise RuntimeError(
                f"Token budget exceeded: need {tokens}, have {self.remaining_tokens}"
            )


# --- usage ---
session = TokenLimitedSession("sess-001", token_limit=4096)
session.add_turn("user", "What is encapsulation?", tokens=8)
session.add_turn("assistant", "Encapsulation bundles data with methods ...", tokens=12)
print(session.remaining_tokens)  # 4076
print(len(session.messages))     # 2
session.close()
