class SamplingConfig:
    def __init__(self, temperature: float = 1.0) -> None:
        self.temperature = temperature  # routes through setter

    @property
    def temperature(self) -> float:
        return self._temperature

    @temperature.setter
    def temperature(self, value: float) -> None:
        if not isinstance(value, (int, float)):
            raise TypeError(f"temperature must be a number, got {type(value).__name__}")
        if not 0.0 <= float(value) <= 2.0:
            raise ValueError(f"temperature {value} is outside [0.0, 2.0]")
        self._temperature = float(value)

    def __repr__(self) -> str:
        return f"SamplingConfig(temperature={self._temperature})"


cfg = SamplingConfig(temperature=0.7)
print(cfg)          # SamplingConfig(temperature=0.7)
cfg.temperature = 1.2
print(cfg)          # SamplingConfig(temperature=1.2)

try:
    cfg.temperature = 3.0
except ValueError as exc:
    print(exc)      # temperature 3.0 is outside [0.0, 2.0]

try:
    cfg.temperature = "hot"
except TypeError as exc:
    print(exc)      # temperature must be a number, got str

