class LLMClient:
    """
    Abstracts all HTTP and retry concerns behind complete() and stream().
    Callers see only: list[dict] in, str out.
    """

    _MAX_RETRIES = 4
    _BASE_DELAY = 0.5   # seconds

    def __init__(self, api_key: str, model: str, base_url: str) -> None:
        self.__api_key = api_key        # never visible in repr or logs
        self._model = model
        self._base_url = base_url.rstrip("/")
        self._total_calls = 0
        self._total_tokens = 0

    # ---- public interface ------------------------------------------------

    def complete(self, messages: list[dict], **opts) -> str:
        """Send messages, return assistant reply text."""
        payload = self._build_payload(messages, opts)
        data = self._post_with_retry("/chat/completions", payload)
        text = self._extract_text(data)
        self._total_tokens += data.get("usage", {}).get("total_tokens", 0)
        return text

    @property
    def stats(self) -> dict:
        return {"calls": self._total_calls, "tokens": self._total_tokens}

    # ---- private implementation -------------------------------------------

    def _build_payload(self, messages: list[dict], opts: dict) -> dict:
        return {"model": self._model, "messages": messages, **opts}

    def _headers(self) -> dict:
        return {
            "Authorization": f"Bearer {self.__api_key}",
            "Content-Type": "application/json",
        }

    def _post_with_retry(self, path: str, payload: dict) -> dict:
        url = self._base_url + path
        last_exc: Exception | None = None
        for attempt in range(self._MAX_RETRIES):
            try:
                self._total_calls += 1
                # Simulate HTTP post (replace with httpx.Client or requests in production)
                response = self._http_post(url, payload)
                return response
            except TransientError as exc:
                last_exc = exc
                delay = self._BASE_DELAY * (2 ** attempt) + random.uniform(0, 0.2)
                time.sleep(delay)
        raise RuntimeError(f"All {self._MAX_RETRIES} retries failed") from last_exc

    def _http_post(self, url: str, payload: dict) -> dict:
        # Placeholder — in real code: httpx.Client().post(url, json=payload, headers=...)
        raise NotImplementedError("Provide a real HTTP implementation")

    def _extract_text(self, data: dict) -> str:
        try:
            return data["choices"][0]["message"]["content"]
        except (KeyError, IndexError) as exc:
            raise ValueError(f"Unexpected response shape: {data}") from exc

    def __repr__(self) -> str:
        # API key is NOT exposed
        return f"LLMClient(model={self._model!r}, base_url={self._base_url!r})"


