from dataclasses import dataclass, field
from typing import ClassVar


# attrs / dataclasses can enforce types at runtime with a validator
# Here we use dataclasses with __post_init__ for invariant checking:
@dataclass
class MessageTurn:
    role: str
    content: str
    tokens: int
    _VALID_ROLES: ClassVar[frozenset] = frozenset({"user", "assistant", "system"})

    def __post_init__(self) -> None:
        if self.role not in self._VALID_ROLES:
            raise ValueError(f"Invalid role: {self.role!r}")
        if self.tokens < 0:
            raise ValueError(f"tokens must be >= 0, got {self.tokens}")
        if not self.content.strip():
            raise ValueError("content must not be blank")

class SecureClient:
    def __init__(self, api_key: str) -> None:
        self.__api_key = api_key      # mangled: _SecureClient__api_key

    def __repr__(self) -> str:
        return f"SecureClient(key=***)"   # key never appears in logs

    def __str__(self) -> str:
        return self.__repr__()

    def _auth_header(self) -> dict:
        return {"Authorization": f"Bearer {self.__api_key}"}

import jsonschema

class ToolExecutor:
    def __init__(self, registry: dict, schemas: dict) -> None:
        self._registry = registry
        self._schemas = schemas

    def execute(self, call: dict) -> dict:
        name = call.get("name", "")
        if name not in self._registry:
            return {"ok": False, "error": f"Unknown tool: {name!r}"}
        # Validation cannot be bypassed — there is no other path to run()
        schema = self._schemas.get(name, {})
        try:
            jsonschema.validate(call.get("args", {}), schema)
        except jsonschema.ValidationError as exc:
            return {"ok": False, "error": f"Invalid args: {exc.message}"}
        try:
            result = self._registry[name].run(**call["args"])
            return {"ok": True, "data": result}
        except Exception as exc:
            return {"ok": False, "error": str(exc)}
